import React, { useEffect, useState } from 'react';
import './App.css';
import CredencialesUsuario from './componentes/credenciales';
import Prueba from './pages/prueba'; // Asegúrate de que la ruta sea correcta
import { Routes, Route } from 'react-router-dom';

function App() {
  const [data, setData] = useState([]);

  useEffect(() => {
    fetch('http://localhost:8081/usuarios')
      .then(res => res.json())
      .then(data => setData(data))
      .catch(err => console.log(err));
  }, []);

  return (
    <div className="App">
      <div className="ventana-de-registro">
        <Routes>
          {/* Solo muestra el registro en la raíz */}
          <Route path="/" element={
            <div className="contenedor-flex-registro">
              <div className="lado-derecho-registro">
                <CredencialesUsuario />
              </div>
              <div className="lado-izquierdo-registro">
                <p className="estilo-de-texto-de-formulario-registro">¡Bienvenidos!</p>
                <p className="estilo-de-texto-de-formulario-registro">Nos alegra muchísimo que estés aquí...</p>
              </div>
            </div>
          } />

          {/* Muestra la prueba en /prueba */}
          <Route path="/prueba" element={<Prueba />} />
        </Routes>
      </div>
    </div>
  );
}

export default App;
